import React, { useEffect, useState } from 'react';
import api from '../services/api';

export default function Appointments(){
  const [appointments, setAppointments] = useState([]);
  const [form, setForm] = useState({doctorId:'',patientId:'',date:'',time:''});

  async function load(){
    const res = await api.get('/appointments');
    setAppointments(res.data);
  }
  useEffect(()=>{load()},[]);

  async function handleBook(e){
    e.preventDefault();
    await api.post('/appointments', form);
    setForm({doctorId:'',patientId:'',date:'',time:''});
    load();
  }

  async function handleCancel(id){
    await api.delete(`/appointments/${id}`);
    load();
  }

  return (
    <div>
      <h2>Appointments</h2>
      <form className="form" onSubmit={handleBook}>
        <input placeholder="Doctor ID" value={form.doctorId} onChange={e=>setForm({...form,doctorId:e.target.value})} required />
        <input placeholder="Patient ID" value={form.patientId} onChange={e=>setForm({...form,patientId:e.target.value})} required />
        <input type="date" value={form.date} onChange={e=>setForm({...form,date:e.target.value})} required />
        <input type="time" value={form.time} onChange={e=>setForm({...form,time:e.target.value})} required />
        <button className="btn">Book</button>
      </form>

      <table className="table">
        <thead><tr><th>ID</th><th>Doctor</th><th>Patient</th><th>Date</th><th>Time</th><th>Actions</th></tr></thead>
        <tbody>
          {appointments.map(a=> (
            <tr key={a.id}>
              <td>{a.id}</td>
              <td>{a.doctor?.name || a.doctorId}</td>
              <td>{a.patient?.name || a.patientId}</td>
              <td>{a.date}</td>
              <td>{a.time}</td>
              <td className="flex">
                <button className="btn" onClick={()=>handleCancel(a.id)}>Cancel</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
